const items = $input.all();
const results = [];
const ON_RAMP_KEYWORDS = [
  'on-ramp', 'on ramp', 'onramp',
  'open season', 'open-season',
  'additional award', 'additional awardee',
  'new entrant', 'new contractor',
  'pool expansion', 'pool addition',
  'add contractor', 'adding contractor',
  'fair opportunity', 'fair consideration',
  'reopen', 're-open', 'reopening',
  'modify holder list', 'add to holder',
  'multiple award', 'mac expansion',
  'idiq modification', 'vehicle modification',
  'sources sought', 'market research',
  'rfi', 'request for information',
  'draft rfp', 'draft solicitation',
  'pre-solicitation', 'presolicitation'
];
for (const item of items) {
  const data = item.json;
  const opps = data.opportunitiesData || data.body?.opportunitiesData || [];
  const idiq = $('Get Target IDIQs').item.json;
  if (opps && opps.length > 0) {
    for (const opp of opps) {
      const title = (opp.title || '').toLowerCase();
      const desc = (opp.description || '').toLowerCase();
      const combined = title + ' ' + desc;
      const matchedKeywords = ON_RAMP_KEYWORDS.filter(kw => combined.includes(kw));
      const isOnRamp = matchedKeywords.length > 0;
      const confidence = isOnRamp ? Math.min(99, 50 + matchedKeywords.length * 15) : 30;
      if (isOnRamp || opps.length <= 3) {
        results.push({ json: {
          idiq_name: idiq.name, idiq_agency: idiq.agency,
          opp_title: opp.title, opp_id: opp.noticeId,
          posted_date: opp.postedDate, response_deadline: opp.responseDeadLine,
          url: 'https://sam.gov/opp/' + (opp.noticeId || ''),
          is_on_ramp: isOnRamp, matched_keywords: matchedKeywords.join(', '),
          confidence: confidence, type: opp.type || 'unknown'
        }});
      }
    }
  }
}
if (results.length === 0) return [{ json: { no_results: true } }];
return results;
